---战斗Buff
---@class LFightBuff
local LFightBuff = LxClass("LFightBuff", nil)
-----------------------------------------------------------------
local LFightEffect = LXImport("..View.LFightEffect")

-----------------------------------------------------------------
function LFightBuff:LFightBuff(battleUnit)
    ---@type LFightUnit
    self._battleUnit = battleUnit
    self._effect = nil
    ---@type number
    self._buffId = -1
    ---@type number 层数
    self._buffUniqueIdCnt = -1
end

function LFightBuff:GetBuffUniqueId()
    return self._buffUniqueId
end

function LFightBuff:GetBuffId()
    return self._buffId
end

function LFightBuff:GetBbuffUniqueIdCnt()
    return self._buffUniqueIdCnt
end

---@param battleObj LFightObject
function LFightBuff:ShowEffect(data,battleObj)
    self._buffUniqueId = data.buffUniqueId
    self._buffId = data.buffId or -1
    self._buffUniqueIdCnt = data.buffUniqueIdCnt or -1

    local parentTrans = data.root
    local pos = data.pos
    local effectName = data.effectName
    local order = data.order
    local dir =  data.dir
    local localPos = data.localPos
    local scale = data.scale or 1
    ---@type LFightEffect
    local eff = LFightEffect:New(self._battleUnit,parentTrans,effectName,pos,dir)
    eff:SetEffectPara({
        order = order,localPos = localPos,scale = scale,buffId = self._buffId,
    })
    if battleObj then
        eff:SetTargetObj(battleObj)
    end
    eff:PlayEffect()
    self._effect = eff
end

function LFightBuff:ResetOrder(order)
    if self._effect then
        self._effect:ResetRenderOrder(order)
    end
end

function LFightBuff:SetVisible(isVisible,isEnd)
    if isVisible and isEnd and self:CheckIsHitShowBuff() then
        isVisible = false
    end
    if self._effect then
        self._effect:SetVisible(isVisible)
    end
end

function LFightBuff:CheckIsHitShowBuff()
    if not self._buffId or self._buffId < 1 then return false end

    return gModelSkill:CheckIsHitShowBuff(self._buffId)
end

function LFightBuff:Destroy()
    if self._effect then
        self._effect:Destroy()
    end
    self._effect = nil

    table.removeall(self)
    self._isDestroy = true
end

return LFightBuff

